-- Create "audit_logs" table
CREATE TABLE "audit_logs" (
  "id" uuid NOT NULL DEFAULT generate_uuidv7(),
  "seq" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "organization_id" text NOT NULL,
  "project_id" uuid NULL,
  "actor_id" text NOT NULL,
  "actor_type" text NOT NULL,
  "actor_display_name" text NULL,
  "actor_slug" text NULL,
  "action" text NOT NULL,
  "subject_id" text NOT NULL,
  "subject_type" text NOT NULL,
  "subject_display_name" text NULL,
  "subject_slug" text NULL,
  "before_snapshot" jsonb NULL,
  "after_snapshot" jsonb NULL,
  "metadata" jsonb NULL,
  "created_at" timestamptz NOT NULL DEFAULT clock_timestamp(),
  PRIMARY KEY ("id")
);
-- Create index "audit_logs_organization_id_project_id_seq_idx" to table: "audit_logs"
CREATE INDEX "audit_logs_organization_id_project_id_seq_idx" ON "audit_logs" ("organization_id", "project_id", "seq" DESC);
-- Create index "audit_logs_organization_id_seq_idx" to table: "audit_logs"
CREATE INDEX "audit_logs_organization_id_seq_idx" ON "audit_logs" ("organization_id", "seq" DESC);
